const axios = require('axios');
const cheerio = require('cheerio');

async function search() {
    const url = 'https://pixeldrain.net/d/CEG3sGRE';
    try {
        const response = await axios.get(url);
        const $ = cheerio.load(response.data);

        // Find all elements that look like folder links (adjust selector as needed)
        const results = [];
        $('a.file-item__link, a[href*="/d/"]').each((i, element) => {
            const href = $(element).attr('href');
            const title = $(element).text().trim() || $(element).find('.file-item__name').text().trim();

            // Filter out the search index file
            if (href && !href.includes('.search_index.gz') && title) {
                // Determine if it's a season folder or episode file based on the name
                const isSeason = /^\d+\s*-\s*/.test(title) && !title.includes('.');
                const seasonMatch = title.match(/^(\d+)\s*-\s*(.+)/);

                results.push({
                    title: title,
                    id: href,
                    // Store metadata for later use
                    meta: {
                        isSeason: isSeason,
                        seasonNumber: seasonMatch ? parseInt(seasonMatch[1], 10) : null,
                        seasonName: seasonMatch ? seasonMatch[2] : title
                    }
                });
            }
        });

        return results;
    } catch (error) {
        console.error('Error fetching from PixelDrain:', error);
        return [];
    }
}

search();

