// This can be used to get a list of seasons/episodes for the catalog view.
// It reuses the search logic to present the structure.
const axios = require('axios');
const cheerio = require('cheerio');

async function catalog() {
    const url = 'https://pixeldrain.net/d/CEG3sGRE';
    try {
        const response = await axios.get(url);
        const $ = cheerio.load(response.data);

        const seasons = {};
        const episodes = {};

        $('a.file-item__link, a[href*="/d/"]').each((i, element) => {
            const href = $(element).attr('href');
            const title = $(element).text().trim() || $(element).find('.file-item__name').text().trim();

            if (!href || href.includes('.search_index.gz') || !title) return;

            const seasonMatch = title.match(/^(\d+)\s*-\s*(.+)/);
            const isSeason = /^\d+\s*-\s*/.test(title) && !title.includes('.');

            if (isSeason && seasonMatch) {
                const seasonNum = parseInt(seasonMatch[1], 10);
                seasons[seasonNum] = {
                    id: href.replace('/d/', ''),
                    name: seasonMatch[2],
                    number: seasonNum
                };
            } else if (!isSeason) {
                // This is likely an episode file - try to determine which season it belongs to
                // For simplicity, we'll add it as a standalone episode
                // In a real implementation, you'd need better logic to map episodes to seasons
                const episodeId = href.replace('/d/', '');
                episodes[episodeId] = {
                    title: title,
                    id: episodeId
                };
            }
        });

        // Return a structured catalog
        return {
            seasons: Object.values(seasons),
            episodes: episodes
        };
    } catch (error) {
        console.error('Error fetching catalog:', error);
        return { seasons: [], episodes: {} };
    }
}

catalog();
